import { GraduationCap, Microscope, Calculator, Atom, BookOpen, Sparkles, Trophy, Target } from "lucide-react";
import { getTranslations } from "next-intl/server";
import { Link } from "@/navigation";

export default async function Home({ params }: { params: Promise<{ locale: string }> }) {
    const { locale } = await params;
    const t = await getTranslations("Landing");

    const subjects = [
        {
            id: "math",
            name: t("subjects.math"),
            icon: <Calculator className="w-8 h-8 text-emerald-600" />,
        },
        {
            id: "physics",
            name: t("subjects.physics"),
            icon: <Atom className="w-8 h-8 text-emerald-600" />,
        },
        {
            id: "biology",
            name: t("subjects.biology"),
            icon: <Microscope className="w-8 h-8 text-emerald-600" />,
        },
        {
            id: "chemistry",
            name: t("subjects.chemistry"),
            icon: <Atom className="w-8 h-8 text-emerald-600" />,
        },
        {
            id: "english",
            name: t("subjects.english"),
            icon: <BookOpen className="w-8 h-8 text-emerald-600" />,
        },
    ];

    const stats = [
        { icon: <Target className="w-5 h-5 text-emerald-500" />, text: t("stats.precision") },
        { icon: <Sparkles className="w-5 h-5 text-emerald-500" />, text: t("stats.optimized") },
        { icon: <Trophy className="w-5 h-5 text-emerald-500" />, text: t("stats.ranked") },
    ];

    return (
        <main className="min-h-screen pb-24 overflow-x-hidden bg-slate-50">
            {/* Hero Section - Dark Mode */}
            <section className="relative pt-32 pb-40 px-6 flex flex-col items-center bg-slate-950 text-white overflow-hidden">
                {/* Glowing Emerald Effect */}
                <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full max-w-6xl aspect-square bg-[radial-gradient(circle_at_50%_0%,rgba(16,185,129,0.15),transparent_70%)] -z-10" />
                <div className="absolute top-1/4 left-1/4 w-96 h-96 bg-emerald-600/20 rounded-full blur-[120px] -z-10" />
                <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-emerald-900/40 rounded-full blur-[100px] -z-10" />

                <div className="flex items-center gap-2 px-4 py-2 bg-emerald-500/10 rounded-full border border-emerald-500/20 mb-10">
                    <Sparkles className="w-4 h-4 text-emerald-400" />
                    <span className="text-xs font-black text-emerald-400 uppercase tracking-widest">{t("badge_new")}</span>
                </div>

                <div className="max-w-5xl w-full text-center space-y-10 relative z-10">
                    <h1 className="text-5xl md:text-7xl lg:text-8xl font-black tracking-tighter leading-[1.1]">
                        Discover your Perfect <br />
                        <span className="text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 to-emerald-600">
                            Academic Journey
                        </span>
                    </h1>

                    <p className="text-xl md:text-2xl text-slate-300 max-w-3xl mx-auto leading-relaxed font-medium">
                        AI-powered guidance to master your subjects and unlock your future.
                    </p>

                    <div className="flex flex-wrap items-center justify-center gap-8 pt-8">
                        {stats.map((stat, i) => (
                            <div key={i} className="flex items-center gap-2 bg-white/5 backdrop-blur-sm px-4 py-2 rounded-full border border-white/10">
                                {stat.icon}
                                <span className="text-xs font-black text-slate-300 uppercase tracking-widest">{stat.text}</span>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Seamless transition divider */}
                <div className="absolute bottom-0 left-0 w-full h-24 bg-gradient-to-b from-transparent to-slate-50 pointer-events-none" />
            </section>

            <div className="max-w-7xl mx-auto px-6 space-y-32 pt-20">
                {/* Academic Subjects Section */}
                <section className="space-y-12">
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                        <div className="space-y-2 text-center md:text-start w-full">
                            <h2 className="text-4xl font-black text-slate-800 tracking-tight">{t("academic_subjects")}</h2>
                            <p className="text-emerald-600 font-bold uppercase text-xs tracking-widest">{t("select_material")}</p>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {subjects.map((s, i) => (
                            <Link
                                href={`/diagnostic?subject=${s.id}`}
                                key={i}
                                className="group relative p-10 rounded-[2.5rem] bg-white/60 backdrop-blur-xl border border-slate-100/80 hover:border-emerald-400 transition-all duration-500 hover:shadow-2xl hover:shadow-emerald-500/15 cursor-pointer overflow-hidden text-center flex flex-col items-center justify-center min-h-[280px]"
                            >
                                {/* Subtle glassmorphism glow on hover */}
                                <div className="absolute inset-0 bg-gradient-to-br from-emerald-50/80 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />

                                <div className="relative z-10 space-y-6 flex flex-col items-center">
                                    <div className="w-24 h-24 rounded-[2rem] bg-white flex items-center justify-center text-emerald-600 group-hover:scale-110 transition-transform duration-500 shadow-sm border border-emerald-100/50">
                                        {s.icon}
                                    </div>
                                    <h3 className="text-3xl font-black text-slate-800 tracking-tight transition-colors group-hover:text-emerald-700">
                                        {s.name}
                                    </h3>
                                </div>
                            </Link>
                        ))}
                    </div>
                </section>

                {/* Features Section */}
                <section className="space-y-12">
                    <div className="text-center space-y-4">
                        <h2 className="text-4xl font-black text-slate-800 tracking-tight">{t("features.title")}</h2>
                        <p className="text-emerald-600 font-bold uppercase text-xs tracking-widest">{t("features.subtitle")}</p>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                        {/* Roadmap Feature */}
                        <div className="p-12 rounded-[3rem] bg-white border border-slate-100 space-y-6 hover:border-emerald-300 transition-all duration-500 hover:shadow-2xl hover:shadow-emerald-500/10 group">
                            <div className="w-20 h-20 bg-emerald-50 rounded-[2rem] flex items-center justify-center group-hover:scale-110 group-hover:rotate-3 transition-all duration-500 border border-emerald-100/50">
                                <Target className="w-10 h-10 text-emerald-600" />
                            </div>
                            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{t("features.roadmap.title")}</h3>
                            <p className="text-slate-500 font-medium leading-relaxed">{t("features.roadmap.desc")}</p>
                        </div>

                        {/* Analytics Feature */}
                        <div className="p-12 rounded-[3rem] bg-white border border-slate-100 space-y-6 hover:border-emerald-300 transition-all duration-500 hover:shadow-2xl hover:shadow-emerald-500/10 group">
                            <div className="w-20 h-20 bg-emerald-50 rounded-[2rem] flex items-center justify-center group-hover:scale-110 group-hover:-rotate-3 transition-all duration-500 border border-emerald-100/50">
                                <Sparkles className="w-10 h-10 text-emerald-600" />
                            </div>
                            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{t("features.analytics_feat.title")}</h3>
                            <p className="text-slate-500 font-medium leading-relaxed">{t("features.analytics_feat.desc")}</p>
                        </div>

                        {/* Predictor Feature */}
                        <div className="p-12 rounded-[3rem] bg-white border border-slate-100 space-y-6 hover:border-emerald-300 transition-all duration-500 hover:shadow-2xl hover:shadow-emerald-500/10 group">
                            <div className="w-20 h-20 bg-emerald-50 rounded-[2rem] flex items-center justify-center group-hover:scale-110 group-hover:rotate-3 transition-all duration-500 border border-emerald-100/50">
                                <Trophy className="w-10 h-10 text-emerald-600" />
                            </div>
                            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{t("features.predictor_feat.title")}</h3>
                            <p className="text-slate-500 font-medium leading-relaxed">{t("features.predictor_feat.desc")}</p>
                        </div>
                    </div>
                </section>
            </div>
        </main>
    );
}
